-- PROYECTO EDUCADORES DE CALLE
-- MIGRACIÓN: CREACIÓN Y CARGA DE LA TABLA MAESTRO_PARAMETROS (ORACLE)
-- =============================================================================

-- 1. CREACIÓN DE LA TABLA
CREATE TABLE MAESTRO_PARAMETROS (
    ID NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    GRUPO VARCHAR2(50) NOT NULL,
    CODIGO VARCHAR2(10) NOT NULL,
    DESCRIPCION VARCHAR2(250) NOT NULL,
    ORDEN NUMBER NOT NULL,
    ESTADO NUMBER(1) DEFAULT 1 NOT NULL
);

-- Índices para búsqueda rápida en consultas por grupo y código
CREATE INDEX IDX_MP_GRUPO ON MAESTRO_PARAMETROS(GRUPO);
CREATE INDEX IDX_MP_GRUPO_ESTADO ON MAESTRO_PARAMETROS(GRUPO, ESTADO);

